module shift_register_8bit(
    input [7:0] d, 
    input load, 
    input clk, 
    output q
);
    reg [7:0] obf_shift_reg;

    always @(posedge clk) begin
        if (load)
            obf_shift_reg <= d;
        else
            obf_shift_reg <= obf_shift_reg >> 1;
    end

    assign q = obf_shift_reg[0];
endmodule
